/** Glimbo_Cost(b, tradeCount) — tradeCount = SAVE Research[12][b] (per-slot trade count, NOT the
 *  CustomLists tier array of the same top-level name). Applies EventShopOwned(38) and
 *  Companions(57) discounts if supplied; both default to "no discount" (0). */
export function glimboCost(b, tradeCount, eventShop38 = 0, companion57 = 0) {
  const row = GLIMBO_TRADES[b];
  if (!row) throw new Error(`Glimbo_Cost(${b}): no GLIMBO_TRADES row`);
  const n = Number(tradeCount ?? 0);
  const raw = (1 + n + 1.5 * n) * Math.pow(row.costGrowth, n) * Math.max(0.1, 1 - 25 * eventShop38 / 100);
  return raw < 1e9 ? Math.floor(Math.max(1, raw * Math.max(0.2, 1 - companion57 / 100))) : raw;
}

