/** Minehead("BonusQTY",b,0) — unchanged formula from bonuses/minehead.mjs's docstring, restated
 *  here operating on the full MINEHEAD_BONUS_QTY table instead of the 1-id MINEHEAD_QTY. `tier` =
 *  SAVE Research[7][4] (a progress/tier counter, per savemap.mjs's Research entry). */
export function mineheadBonusQtyFull(b, tier) {
  const row = MINEHEAD_BONUS_QTY[b];
  if (!row) throw new Error(`Minehead BonusQTY(${b}): no MINEHEAD_BONUS_QTY row`);
  return Number(tier ?? 0) > b ? row.coeff : 0;
}
